const text = ($input.first().json.chatInput || "").toLowerCase();

// Busca: "nicsp 02", "nicsp-2", "norma 3", "la 4", "02"
const m =
  text.match(/nicsp[\s-]*0*([1-9]\d?)/i) ||
  text.match(/norma[\s-]*0*([1-9]\d?)/i) ||
  text.match(/\bla[\s-]*0*([1-9]\d?)\b/i) ||
  text.match(/\b([1-9]\d?)(era|ra|da|ta)\b/i);


let normaId = null;

if (m) {
  const n = parseInt(m[1], 10);
  if (n >= 1 && n <= 99) {
    normaId = `NICSP-${String(n).padStart(2, "0")}`;
  }
}

return [{ json: { ...$json, norma_id: normaId } }];

let q = ($json.chatInput || "").trim();

// Si ya tengo una norma detectada
if ($json.norma_id) {
  q = `Resumen, objetivo, alcance y definiciones de ${$json.norma_id}`;
}

return [{ json: { ...$json, rag_query: q } }];

const rows = items.map(i => i.json);

const rag_context = rows.map((r, idx) => {
  const m = r.metadata || {};
  return [
    `Chunk ${idx + 1}`,
    `chunk_id: ${r.chunk_id || m.chunk_id || ""}`,
    `norma_id: ${m.norma_id || ""}`,
    `sección: ${m.seccion || ""}`,
    `subsección: ${m.subseccion || ""}`,
    `similarity: ${r.similarity ?? ""}`,
    `texto:\n${(r.text || "").trim()}`,
  ].join("\n");
}).join("\n\n---\n\n");

// 👇 Esto es lo que arregla tu error de paired item
return [{
  json: {
    rag_rows: rows,
    rag_context,
  },
  pairedItem: rows.map((_, i) => ({ item: i })),
}];
